<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>
    <div class="thread-root-message">
        <span class="message-author">@RootMessage.Author</span>
        <p>@RootMessage.Content</p>
    </div>
    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="message-author">@reply.Author</span>
                    <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="message-content">@reply.Content</div>
            </div>
        }
    </div>
    <div class="thread-input">
        <textarea @bind="ReplyText" @bind:event="oninput"
                  placeholder="Reply…"
                  @onkeydown="HandleKeyDown"></textarea>
        <button @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(ReplyText)">Reply</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Message RootMessage { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<Message> Replies { get; set; } = [];

    [Parameter]
    public EventCallback OnClose { get; set; }

    [Parameter]
    public EventCallback<string> OnSendReply { get; set; }

    private string ReplyText { get; set; } = "";

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(ReplyText)) return;
        var text = ReplyText;
        ReplyText = "";
        await OnSendReply.InvokeAsync(text);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}
"}

