@using sv_961da1a81ece4da9b88728cea7726788.Services

<div class="channel-list">
    <h3 class="channel-list-header">Channels</h3>
    @foreach (var channel in Channels)
    {
        <div class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
             @onclick="() => OnChannelSelected.InvokeAsync(channel)">
            <div class="channel-info">
                <span class="channel-name"># @channel.Name</span>
                <span class="channel-description">@Truncate(channel.Description, 40)</span>
            </div>
            @if (channel.UnreadCount > 0)
            {
                <span class="unread-badge">@channel.UnreadCount</span>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int? ActiveChannelId { get; set; }

    [Parameter]
    public EventCallback<Channel> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-list {
    padding: 12px 0;
}

.channel-list-header {
    padding: 0 16px 8px;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    margin: 0;
}

.channel-item {
    display: flex;
    align-items: center;
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 1px 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #34373c;
}

.channel-item.active {
    background: #393c43;
    color: #fff;
}

.channel-info {
    flex: 1;
    min-width: 0;
}

.channel-name {
    display: block;
    font-weight: 500;
    font-size: 0.95rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-description {
    display: block;
    font-size: 0.75rem;
    color: #72767d;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    margin-left: 8px;
    flex-shrink: 0;
}

