toolArgs.file_text:
.message-item {
    position: relative;
    padding: 6px 12px;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    font-size: 0.95rem;
    line-height: 1.4;
    word-wrap: break-word;
}

.message-reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #dcddde;
}

.reaction-badge:hover {
    background: #40444b;
    border-color: #5865f2;
}

.thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -10px;
    right: 8px;
    display: none;
    background: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
}

.message-item:hover .message-actions {
    display: flex;
    align-items: center;
    gap: 2px;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    cursor: pointer;
    font-size: 0.8rem;
    padding: 4px 8px;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #40444b;
    color: #dcddde;
}

