@page "/chat"
@using sv_961da1a81ece4da9b88728cea7726788.Services
@using sv_961da1a81ece4da9b88728cea7726788.Components.Chat
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <aside class="chat-sidebar">
        <ChannelList Channels="_channels"
                     ActiveChannelId="_selectedChannel?.Id"
                     OnChannelSelected="SelectChannel" />
    </aside>

    <main class="chat-main @(_isThreadOpen ? "" : "expanded")">
        @if (_selectedChannel is not null)
        {
            <div class="channel-header">
                <h2># @_selectedChannel.Name</h2>
                <p>@_selectedChannel.Description</p>
            </div>
            <div class="message-list" @ref="_messageListRef">
                @if (_hasMore)
                {
                    <div class="scroll-sentinel" @ref="_sentinelRef"></div>
                }
                @if (_isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var message in _messages)
                {
                    <MessageItem Message="message"
                                 ReplyCount="GetReplyCount(message.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="HandleReaction" />
                }
            </div>
            <div class="message-input">
                <textarea @bind="NewMessage" @bind:event="oninput"
                          placeholder="Message #@_selectedChannel.Name"
                          @onkeydown="HandleMainKeyDown"></textarea>
                <button @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessage)">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @if (_isThreadOpen && _threadRootMessage is not null && _threadReplies is not null)
    {
        <aside class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </aside>
    }
</div>

@code {
    private const int PageSize = 50;

    private List<Channel> _channels = [];
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _replyCounts = new();

    private string NewMessage { get; set; } = "";

    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private bool _isThreadOpen;

    private int _skip;
    private bool _hasMore = true;
    private bool _isLoadingMore;
    private double _previousScrollHeight;

    private bool _shouldScrollToBottom;
    private bool _shouldObserveSentinel;
    private bool _needsScrollAdjust;

    private ElementReference _messageListRef;
    private ElementReference _sentinelRef;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0]);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
        }

        if (_shouldScrollToBottom && _jsModule is not null)
        {
            _shouldScrollToBottom = false;
            await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
        }

        if (_needsScrollAdjust && _jsModule is not null)
        {
            _needsScrollAdjust = false;
            await _jsModule.InvokeVoidAsync("adjustScroll", _messageListRef, _previousScrollHeight);
        }

        if (_shouldObserveSentinel && _jsModule is not null && _dotNetRef is not null && _hasMore)
        {
            _shouldObserveSentinel = false;
            await _jsModule.InvokeVoidAsync("observeSentinel", _sentinelRef, _messageListRef, _dotNetRef);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        _selectedChannel = channel;
        _skip = 0;
        _hasMore = true;
        _isLoadingMore = false;
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;
        _hasMore = messages.Count == PageSize;
        ComputeReplyCounts();

        _shouldScrollToBottom = true;
        _shouldObserveSentinel = true;

        // Mark channel as read and update local unread count
        _ = ChatService.MarkChannelReadAsync(channel.Id);
        var idx = _channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            _channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (_isLoadingMore || !_hasMore || _selectedChannel is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        _previousScrollHeight = _jsModule is not null
            ? await _jsModule.InvokeAsync<double>("getScrollHeight", _messageListRef)
            : 0;

        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _skip, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            _skip += older.Count;
            ComputeReplyCounts();
        }

        _hasMore = older.Count == PageSize;
        _isLoadingMore = false;
        _needsScrollAdjust = _previousScrollHeight > 0;

        if (_hasMore)
        {
            _shouldObserveSentinel = true;
        }

        StateHasChanged();
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(NewMessage) || _selectedChannel is null) return;

        var text = NewMessage;
        NewMessage = "";
        var msg = await ChatService.SendMessageAsync(_selectedChannel.Id, text, null);
        _messages.Add(msg);
        _skip++;
        _shouldScrollToBottom = true;
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task OpenThread(Message message)
    {
        _threadRootMessage = message;
        _threadReplies = await ChatService.GetThreadAsync(message.Id);
        _isThreadOpen = true;
        ComputeReplyCounts();
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            _threadRootMessage.ChannelId, content, _threadRootMessage.Id);
        _threadReplies?.Add(reply);
        ComputeReplyCounts();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        UpdateReaction(_messages, args.MessageId, args.Emoji);
        if (_threadReplies is not null)
        {
            UpdateReaction(_threadReplies, args.MessageId, args.Emoji);
        }
    }

    private static void UpdateReaction(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reaction = msg.Reactions.Find(r => r.Emoji == emoji);
        if (reaction is not null)
        {
            reaction.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void ComputeReplyCounts()
    {
        _replyCounts.Clear();

        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts.TryGetValue(rootId, out var count);
            _replyCounts[rootId] = count + 1;
        }

        // Include thread reply count when a thread is loaded
        if (_threadReplies is not null && _threadRootMessage is not null)
        {
            _replyCounts[_threadRootMessage.Id] = _threadReplies.Count;
        }
    }

    private int GetReplyCount(int messageId) =>
        _replyCounts.GetValueOrDefault(messageId);

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("dispose");
            await _jsModule.DisposeAsync();
        }

        _dotNetRef?.Dispose();
    }
}

let observer = null;

export function observeSentinel(sentinel, container, dotNetRef) {
    if (observer) {
        observer.disconnect();
    }

    observer = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting) {
            observer.disconnect();
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    }, { root: container, threshold: 0.1 });

    observer.observe(sentinel);
}

export function scrollToBottom(container) {
    if (container) {
        container.scrollTop = container.scrollHeight;
    }
}

export function getScrollHeight(container) {
    return container ? container.scrollHeight : 0;
}

export function adjustScroll(container, previousScrollHeight) {
    if (container) {
        container.scrollTop = container.scrollHeight - previousScrollHeight;
    }
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

