toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    border-right: 1px solid #202225;
    overflow-y: auto;
}

.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
}

.chat-main.expanded {
    width: 80%;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    border-left: 1px solid #202225;
    background: #36393f;
    color: #dcddde;
}

.channel-header {
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-header p {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #72767d;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.scroll-sentinel {
    height: 1px;
    width: 100%;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #72767d;
    font-size: 0.85rem;
}

.message-input {
    padding: 12px 16px;
    border-top: 1px solid #202225;
    display: flex;
    gap: 8px;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    padding: 10px 12px;
    border: none;
    border-radius: 8px;
    background: #40444b;
    color: #dcddde;
    font-size: 0.95rem;
    font-family: inherit;
    min-height: 40px;
    max-height: 120px;
}

.message-input textarea::placeholder {
    color: #72767d;
}

.message-input button {
    padding: 8px 20px;
    border: none;
    border-radius: 4px;
    background: #5865f2;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
}

.message-input button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.message-input button:hover:not(:disabled) {
    background: #4752c4;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

